external_knowledge:
- 'phenotype' refers to medical conditions or characteristics defined by a specific code;
- 'associated files' are data files linked to a phenotype used for research or analysis;
- 'access events' are recorded incidents when the phenotype data was viewed or utilized by users.

sql:
SELECT phecode_id, number_of_cases
FROM phenotypes
ORDER BY number_of_cases DESC;

SELECT phenotype_description, SUM(number_of_cases) AS total_cases
FROM phenotypes
GROUP BY phenotype_description;

SELECT phenotype_description
FROM phenotypes
WHERE phecode = '8.5';

SELECT number_of_cases
FROM phenotypes
WHERE phecode = 'PheCode_008';

SELECT number_of_cases AS total_cases
FROM phenotypes
WHERE phecode_id = 1;

SELECT AVG(number_of_cases) AS average_cases, AVG(number_of_controls) AS average_controls
FROM phenotypes
WHERE phenotype_category = 1;

SELECT phenotype_description, number_of_cases
FROM phenotypes
ORDER BY number_of_cases DESC;

SELECT phenotype_description
FROM phenotypes
WHERE number_of_controls > (
    SELECT AVG(number_of_controls)
    FROM phenotypes
);
